import{_ as a,o,c as t,ai as d}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"仪表板","description":"","frontmatter":{"read_when":["更改仪表板认证或暴露模式"],"summary":"Gateway 网关仪表板（控制 UI）访问和认证","title":"仪表板","x-i18n":{"generated_at":"2026-02-03T10:13:14Z","model":"claude-opus-4-5","provider":"pi","source_hash":"e6876d50e17d3dd741471ed78bef6ac175b2fdbdc1c45dd52d9d2bd013e17f31","source_path":"web/dashboard.md","workflow":15}},"headers":[],"relativePath":"zh-CN/web/dashboard.md","filePath":"zh-CN/web/dashboard.md","lastUpdated":null}'),l={name:"zh-CN/web/dashboard.md"};function c(r,e,s,n,i,h){return o(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="仪表板-控制-ui" tabindex="-1"><a class="header-anchor" href="#仪表板-控制-ui">#</a> 仪表板（控制 UI）</h1><p>Gateway 网关仪表板是默认在 <code>/</code> 提供的浏览器控制 UI （通过 <code>gateway.controlUi.basePath</code> 覆盖）。</p><p>快速打开（本地 Gateway 网关）：</p><ul><li><a href="http://127.0.0.1:18789/%EF%BC%88%E6%88%96" target="_blank" rel="noreferrer">http://127.0.0.1:18789/（或</a> <code>http://localhost:18789/</code>）</li></ul><p>关键参考：</p><ul><li><a href="/docs/web/control-ui">控制 UI</a> 了解使用方法和 UI 功能。</li><li><a href="/docs/gateway/tailscale">Tailscale</a> 了解 Serve/Funnel 自动化。</li><li><a href="/docs/web/index">Web 界面</a> 了解绑定模式和安全注意事项。</li></ul><p>认证通过 <code>connect.params.auth</code>（token 或密码）在 WebSocket 握手时强制执行。 参见 <a href="/docs/gateway/configuration">Gateway 网关配置</a> 中的 <code>gateway.auth</code>。</p><p>安全注意事项：控制 UI 是一个<strong>管理界面</strong>（聊天、配置、执行审批）。 不要公开暴露它。UI 在首次加载后将 token 存储在 <code>localStorage</code> 中。 优先使用 localhost、Tailscale Serve 或 SSH 隧道。</p><h2 id="快速路径-推荐" tabindex="-1"><a class="header-anchor" href="#快速路径-推荐">#</a> 快速路径（推荐）</h2><ul><li>新手引导后，CLI 现在会自动打开带有你的 token 的仪表板，并打印相同的带 token 链接。</li><li>随时重新打开：<code>opensoul dashboard</code>（复制链接，如果可能则打开浏览器，如果是无头环境则显示 SSH 提示）。</li><li>token 保持本地（仅查询参数）；UI 在首次加载后移除它并保存到 localStorage。</li></ul><h2 id="token-基础-本地-vs-远程" tabindex="-1"><a class="header-anchor" href="#token-基础-本地-vs-远程">#</a> Token 基础（本地 vs 远程）</h2><ul><li><strong>Localhost</strong>：打开 <code>http://127.0.0.1:18789/</code>。如果你看到&quot;unauthorized&quot;，运行 <code>opensoul dashboard</code> 并使用带 token 的链接（<code>?token=...</code>）。</li><li><strong>Token 来源</strong>：<code>gateway.auth.token</code>（或 <code>OPENSOUL_GATEWAY_TOKEN</code>）；UI 在首次加载后存储它。</li><li><strong>非 localhost</strong>：使用 Tailscale Serve（如果 <code>gateway.auth.allowTailscale: true</code> 则无需 token）、带 token 的 tailnet 绑定，或 SSH 隧道。参见 <a href="/docs/web/index">Web 界面</a>。</li></ul><h2 id="如果你看到-unauthorized-1008" tabindex="-1"><a class="header-anchor" href="#如果你看到-unauthorized-1008">#</a> 如果你看到&quot;unauthorized&quot; / 1008</h2><ul><li>运行 <code>opensoul dashboard</code> 获取新的带 token 链接。</li><li>确保 Gateway 网关可达（本地：<code>opensoul status</code>；远程：SSH 隧道 <code>ssh -N -L 18789:127.0.0.1:18789 user@host</code> 然后打开 <code>http://127.0.0.1:18789/?token=...</code>）。</li><li>在仪表板设置中，粘贴你在 <code>gateway.auth.token</code>（或 <code>OPENSOUL_GATEWAY_TOKEN</code>）中配置的相同 token。</li></ul>',14)])])}const _=a(l,[["render",c]]);export{p as __pageData,_ as default};
